/**
 * @jest-environment node
 */
import {
  filterTemplates,
  searchTemplates,
  sortTemplates,
  validateSubmission,
  validateReview,
  computeAverageRating,
  paginateResults,
  getCategoryStats,
  getPopularTags,
  isTemplateFree,
  canUserReview,
  formatPrice,
  TEMPLATE_CATEGORIES,
  DEFAULT_PAGE_SIZE,
  type MarketplaceTemplate,
  type TemplateReview,
  type TemplateSubmission,
} from '@/lib/marketplace/template-marketplace';

// ─── Fixtures ──────────────────────────────────────────────────────────────────

function makeTemplate(
  overrides: Partial<MarketplaceTemplate> = {}
): MarketplaceTemplate {
  return {
    id: 'tpl-1',
    title: 'Template de Teste',
    description: 'Uma descrição de teste para o template',
    category: 'education',
    tags: ['aula', 'educação'],
    thumbnail: '/thumb.jpg',
    authorId: 'author-1',
    authorName: 'João Silva',
    slidesCount: 10,
    duration: 120,
    resolution: '1080p',
    format: 'presentation',
    price: 0,
    currency: 'BRL',
    downloads: 100,
    rating: 4.5,
    reviewCount: 20,
    featured: false,
    communitySubmission: false,
    status: 'published',
    createdAt: '2025-12-01T00:00:00Z',
    updatedAt: '2025-12-01T00:00:00Z',
    ...overrides,
  };
}

function makeReview(
  overrides: Partial<TemplateReview> = {}
): TemplateReview {
  return {
    id: 'rev-1',
    templateId: 'tpl-1',
    userId: 'user-1',
    userName: 'Maria',
    rating: 4,
    comment: 'Ótimo template, muito útil!',
    createdAt: '2025-12-02T00:00:00Z',
    ...overrides,
  };
}

function makeSubmission(
  overrides: Partial<TemplateSubmission> = {}
): TemplateSubmission {
  return {
    title: 'Meu Novo Template',
    description: 'Um template incrível para educação',
    category: 'education',
    tags: ['aula'],
    format: 'presentation',
    price: 0,
    slidesData: { slides: [] },
    ...overrides,
  };
}

const sampleTemplates: MarketplaceTemplate[] = [
  makeTemplate({
    id: '1',
    title: 'Aula de Matemática',
    category: 'education',
    tags: ['matemática', 'aula'],
    price: 0,
    downloads: 500,
    rating: 4.8,
    featured: true,
    createdAt: '2025-12-10T00:00:00Z',
  }),
  makeTemplate({
    id: '2',
    title: 'Pitch Deck Startups',
    category: 'business',
    tags: ['pitch', 'startup'],
    price: 29.9,
    downloads: 200,
    rating: 4.2,
    format: 'presentation',
    createdAt: '2025-12-05T00:00:00Z',
  }),
  makeTemplate({
    id: '3',
    title: 'Post Instagram Marketing',
    category: 'social_media',
    tags: ['instagram', 'marketing'],
    price: 9.9,
    downloads: 1000,
    rating: 4.6,
    format: 'social',
    createdAt: '2025-12-08T00:00:00Z',
  }),
  makeTemplate({
    id: '4',
    title: 'Tutorial de React',
    category: 'tutorial',
    tags: ['react', 'programação', 'tutorial'],
    price: 0,
    downloads: 300,
    rating: 3.5,
    format: 'tutorial',
    createdAt: '2025-12-01T00:00:00Z',
  }),
  makeTemplate({
    id: '5',
    title: 'Campanha E-commerce Black Friday',
    category: 'ecommerce',
    tags: ['ecommerce', 'black friday', 'marketing'],
    price: 49.9,
    downloads: 50,
    rating: 5.0,
    format: 'marketing',
    featured: true,
    createdAt: '2025-12-12T00:00:00Z',
  }),
];

// ─── Tests ─────────────────────────────────────────────────────────────────────

describe('template-marketplace', () => {
  // ── TEMPLATE_CATEGORIES ───────────────────────────────────────────────────
  describe('TEMPLATE_CATEGORIES', () => {
    it('should have exactly 10 categories', () => {
      expect(TEMPLATE_CATEGORIES).toHaveLength(10);
    });

    it('each category should have value, label, and icon', () => {
      for (const cat of TEMPLATE_CATEGORIES) {
        expect(cat).toHaveProperty('value');
        expect(cat).toHaveProperty('label');
        expect(cat).toHaveProperty('icon');
        expect(typeof cat.value).toBe('string');
        expect(typeof cat.label).toBe('string');
        expect(typeof cat.icon).toBe('string');
      }
    });
  });

  // ── DEFAULT_PAGE_SIZE ─────────────────────────────────────────────────────
  describe('DEFAULT_PAGE_SIZE', () => {
    it('should be 12', () => {
      expect(DEFAULT_PAGE_SIZE).toBe(12);
    });
  });

  // ── filterTemplates ───────────────────────────────────────────────────────
  describe('filterTemplates', () => {
    it('should return all published templates with no filter', () => {
      const result = filterTemplates(sampleTemplates, {});
      expect(result.total).toBe(5);
      expect(result.templates.length).toBe(5);
    });

    it('should filter by category', () => {
      const result = filterTemplates(sampleTemplates, {
        category: 'education',
      });
      expect(result.total).toBe(1);
      expect(result.templates[0].id).toBe('1');
    });

    it('should filter by search', () => {
      const result = filterTemplates(sampleTemplates, { search: 'react' });
      expect(result.total).toBe(1);
      expect(result.templates[0].id).toBe('4');
    });

    it('should filter by price range (free)', () => {
      const result = filterTemplates(sampleTemplates, { priceRange: 'free' });
      expect(result.total).toBe(2);
      expect(result.templates.every((t) => t.price === 0)).toBe(true);
    });

    it('should filter by price range (paid)', () => {
      const result = filterTemplates(sampleTemplates, { priceRange: 'paid' });
      expect(result.total).toBe(3);
      expect(result.templates.every((t) => t.price > 0)).toBe(true);
    });

    it('should filter by minimum rating', () => {
      const result = filterTemplates(sampleTemplates, { minRating: 4.5 });
      expect(result.total).toBe(3);
    });

    it('should filter by format', () => {
      const result = filterTemplates(sampleTemplates, { format: 'tutorial' });
      expect(result.total).toBe(1);
      expect(result.templates[0].id).toBe('4');
    });

    it('should filter by featured', () => {
      const result = filterTemplates(sampleTemplates, { featured: true });
      expect(result.total).toBe(2);
    });

    it('should apply combined filters', () => {
      const result = filterTemplates(sampleTemplates, {
        priceRange: 'free',
        minRating: 4.0,
      });
      expect(result.total).toBe(1);
      expect(result.templates[0].id).toBe('1');
    });
  });

  // ── searchTemplates ───────────────────────────────────────────────────────
  describe('searchTemplates', () => {
    it('should match by title', () => {
      const results = searchTemplates(sampleTemplates, 'Matemática');
      expect(results).toHaveLength(1);
      expect(results[0].id).toBe('1');
    });

    it('should match by description', () => {
      const templates = [
        makeTemplate({ id: 'x', description: 'Template para vendas online' }),
      ];
      const results = searchTemplates(templates, 'vendas');
      expect(results).toHaveLength(1);
    });

    it('should match by tag', () => {
      const results = searchTemplates(sampleTemplates, 'instagram');
      expect(results).toHaveLength(1);
      expect(results[0].id).toBe('3');
    });

    it('should match by authorName', () => {
      const templates = [
        makeTemplate({ id: 'a', authorName: 'Carlos Drummond' }),
      ];
      const results = searchTemplates(templates, 'drummond');
      expect(results).toHaveLength(1);
    });

    it('should return no results for unmatched query', () => {
      const results = searchTemplates(sampleTemplates, 'xyznonexistent');
      expect(results).toHaveLength(0);
    });

    it('should be case insensitive', () => {
      const results = searchTemplates(sampleTemplates, 'REACT');
      expect(results).toHaveLength(1);
      expect(results[0].id).toBe('4');
    });

    it('should return all for empty query', () => {
      const results = searchTemplates(sampleTemplates, '');
      expect(results).toHaveLength(5);
    });
  });

  // ── sortTemplates ─────────────────────────────────────────────────────────
  describe('sortTemplates', () => {
    it('should sort by newest', () => {
      const sorted = sortTemplates(sampleTemplates, 'newest');
      expect(sorted[0].id).toBe('5'); // Dec 12
      expect(sorted[1].id).toBe('1'); // Dec 10
    });

    it('should sort by popular', () => {
      const sorted = sortTemplates(sampleTemplates, 'popular');
      expect(sorted[0].id).toBe('3'); // 1000 downloads
      expect(sorted[1].id).toBe('1'); // 500 downloads
    });

    it('should sort by rating', () => {
      const sorted = sortTemplates(sampleTemplates, 'rating');
      expect(sorted[0].id).toBe('5'); // 5.0
      expect(sorted[1].id).toBe('1'); // 4.8
    });

    it('should sort by price_asc', () => {
      const sorted = sortTemplates(sampleTemplates, 'price_asc');
      expect(sorted[0].price).toBe(0);
      expect(sorted[sorted.length - 1].price).toBe(49.9);
    });

    it('should sort by price_desc', () => {
      const sorted = sortTemplates(sampleTemplates, 'price_desc');
      expect(sorted[0].price).toBe(49.9);
      expect(sorted[sorted.length - 1].price).toBe(0);
    });

    it('should not mutate the original array', () => {
      const copy = [...sampleTemplates];
      sortTemplates(sampleTemplates, 'newest');
      expect(sampleTemplates.map((t) => t.id)).toEqual(copy.map((t) => t.id));
    });
  });

  // ── validateSubmission ────────────────────────────────────────────────────
  describe('validateSubmission', () => {
    it('should return no errors for a valid submission', () => {
      const errors = validateSubmission(makeSubmission());
      expect(errors).toHaveLength(0);
    });

    it('should reject missing title', () => {
      const errors = validateSubmission(makeSubmission({ title: '' }));
      expect(errors.length).toBeGreaterThan(0);
      expect(errors[0]).toContain('Título');
    });

    it('should reject short title (< 3 chars)', () => {
      const errors = validateSubmission(makeSubmission({ title: 'AB' }));
      expect(errors.some((e) => e.includes('Título'))).toBe(true);
    });

    it('should reject short description (< 10 chars)', () => {
      const errors = validateSubmission(makeSubmission({ description: 'curta' }));
      expect(errors.some((e) => e.includes('Descrição'))).toBe(true);
    });

    it('should reject invalid category', () => {
      const errors = validateSubmission(
        makeSubmission({ category: 'invalid_cat' as never })
      );
      expect(errors.some((e) => e.includes('Categoria'))).toBe(true);
    });

    it('should reject too many tags (> 10)', () => {
      const tags = Array.from({ length: 11 }, (_, i) => `tag-${i}`);
      const errors = validateSubmission(makeSubmission({ tags }));
      expect(errors.some((e) => e.includes('tag'))).toBe(true);
    });

    it('should reject empty tags', () => {
      const errors = validateSubmission(makeSubmission({ tags: [] }));
      expect(errors.some((e) => e.includes('tag'))).toBe(true);
    });

    it('should reject negative price', () => {
      const errors = validateSubmission(makeSubmission({ price: -5 }));
      expect(errors.some((e) => e.includes('Preço'))).toBe(true);
    });

    it('should accept price of 0 (free)', () => {
      const errors = validateSubmission(makeSubmission({ price: 0 }));
      expect(errors.filter((e) => e.includes('Preço'))).toHaveLength(0);
    });
  });

  // ── validateReview ────────────────────────────────────────────────────────
  describe('validateReview', () => {
    it('should return no errors for a valid review', () => {
      const errors = validateReview({
        templateId: 'tpl-1',
        userId: 'user-1',
        userName: 'Maria',
        rating: 5,
        comment: 'Excelente template!',
      });
      expect(errors).toHaveLength(0);
    });

    it('should reject invalid rating (0)', () => {
      const errors = validateReview({
        templateId: 'tpl-1',
        userId: 'user-1',
        userName: 'Maria',
        rating: 0,
        comment: 'Teste comentário',
      });
      expect(errors.some((e) => e.includes('Avaliação'))).toBe(true);
    });

    it('should reject invalid rating (6)', () => {
      const errors = validateReview({
        templateId: 'tpl-1',
        userId: 'user-1',
        userName: 'Maria',
        rating: 6,
        comment: 'Teste comentário',
      });
      expect(errors.some((e) => e.includes('Avaliação'))).toBe(true);
    });

    it('should reject non-integer rating', () => {
      const errors = validateReview({
        templateId: 'tpl-1',
        userId: 'user-1',
        userName: 'Maria',
        rating: 3.5,
        comment: 'Teste comentário',
      });
      expect(errors.some((e) => e.includes('Avaliação'))).toBe(true);
    });

    it('should reject short comment (< 5 chars)', () => {
      const errors = validateReview({
        templateId: 'tpl-1',
        userId: 'user-1',
        userName: 'Maria',
        rating: 4,
        comment: 'abc',
      });
      expect(errors.some((e) => e.includes('Comentário'))).toBe(true);
    });
  });

  // ── computeAverageRating ──────────────────────────────────────────────────
  describe('computeAverageRating', () => {
    it('should return 0 for empty array', () => {
      expect(computeAverageRating([])).toBe(0);
    });

    it('should return the rating for a single review', () => {
      expect(computeAverageRating([makeReview({ rating: 4 })])).toBe(4);
    });

    it('should compute correct average for multiple reviews', () => {
      const reviews = [
        makeReview({ rating: 5 }),
        makeReview({ rating: 3, id: 'r2' }),
        makeReview({ rating: 4, id: 'r3' }),
      ];
      expect(computeAverageRating(reviews)).toBe(4);
    });

    it('should round to 1 decimal', () => {
      const reviews = [
        makeReview({ rating: 5 }),
        makeReview({ rating: 4, id: 'r2' }),
        makeReview({ rating: 4, id: 'r3' }),
      ];
      // (5+4+4)/3 = 4.333... → 4.3
      expect(computeAverageRating(reviews)).toBe(4.3);
    });
  });

  // ── paginateResults ───────────────────────────────────────────────────────
  describe('paginateResults', () => {
    it('should return first page correctly', () => {
      const result = paginateResults(sampleTemplates, 1, 2);
      expect(result.templates).toHaveLength(2);
      expect(result.page).toBe(1);
      expect(result.total).toBe(5);
      expect(result.totalPages).toBe(3);
      expect(result.hasMore).toBe(true);
    });

    it('should return last page correctly', () => {
      const result = paginateResults(sampleTemplates, 3, 2);
      expect(result.templates).toHaveLength(1);
      expect(result.page).toBe(3);
      expect(result.hasMore).toBe(false);
    });

    it('should clamp out of bounds page', () => {
      const result = paginateResults(sampleTemplates, 100, 2);
      expect(result.page).toBe(3); // clamped to last page
      expect(result.templates).toHaveLength(1);
    });

    it('should handle empty array', () => {
      const result = paginateResults([], 1, 10);
      expect(result.total).toBe(0);
      expect(result.templates).toHaveLength(0);
      expect(result.totalPages).toBe(1);
      expect(result.hasMore).toBe(false);
    });

    it('should handle pageSize larger than total', () => {
      const result = paginateResults(sampleTemplates, 1, 100);
      expect(result.templates).toHaveLength(5);
      expect(result.totalPages).toBe(1);
      expect(result.hasMore).toBe(false);
    });
  });

  // ── getCategoryStats ──────────────────────────────────────────────────────
  describe('getCategoryStats', () => {
    it('should return all-zero counts for empty templates', () => {
      const stats = getCategoryStats([]);
      expect(stats.education).toBe(0);
      expect(stats.business).toBe(0);
      expect(Object.keys(stats)).toHaveLength(10);
    });

    it('should count templates per category', () => {
      const stats = getCategoryStats(sampleTemplates);
      expect(stats.education).toBe(1);
      expect(stats.business).toBe(1);
      expect(stats.social_media).toBe(1);
      expect(stats.tutorial).toBe(1);
      expect(stats.ecommerce).toBe(1);
      expect(stats.marketing).toBe(0);
    });
  });

  // ── getPopularTags ────────────────────────────────────────────────────────
  describe('getPopularTags', () => {
    it('should return empty for no templates', () => {
      expect(getPopularTags([])).toHaveLength(0);
    });

    it('should rank tags by frequency', () => {
      const tags = getPopularTags(sampleTemplates);
      // 'marketing' appears in templates 3 and 5
      const marketingTag = tags.find((t) => t.tag === 'marketing');
      expect(marketingTag).toBeDefined();
      expect(marketingTag?.count).toBe(2);
    });

    it('should respect limit', () => {
      const tags = getPopularTags(sampleTemplates, 3);
      expect(tags.length).toBeLessThanOrEqual(3);
    });

    it('should normalise tag casing', () => {
      const templates = [
        makeTemplate({ id: 'a', tags: ['React'] }),
        makeTemplate({ id: 'b', tags: ['react'] }),
      ];
      const tags = getPopularTags(templates);
      const reactTag = tags.find((t) => t.tag === 'react');
      expect(reactTag?.count).toBe(2);
    });
  });

  // ── isTemplateFree ────────────────────────────────────────────────────────
  describe('isTemplateFree', () => {
    it('should return true for price 0', () => {
      expect(isTemplateFree(makeTemplate({ price: 0 }))).toBe(true);
    });

    it('should return false for price > 0', () => {
      expect(isTemplateFree(makeTemplate({ price: 9.9 }))).toBe(false);
    });
  });

  // ── canUserReview ─────────────────────────────────────────────────────────
  describe('canUserReview', () => {
    it('should allow review from different user with no existing reviews', () => {
      const template = makeTemplate({ authorId: 'author-1' });
      expect(canUserReview('user-99', template, [])).toBe(true);
    });

    it('should disallow review from the template author', () => {
      const template = makeTemplate({ authorId: 'author-1' });
      expect(canUserReview('author-1', template, [])).toBe(false);
    });

    it('should disallow duplicate review from same user', () => {
      const template = makeTemplate({ authorId: 'author-1' });
      const reviews = [makeReview({ userId: 'user-5' })];
      expect(canUserReview('user-5', template, reviews)).toBe(false);
    });

    it('should allow review when other users have reviewed', () => {
      const template = makeTemplate({ authorId: 'author-1' });
      const reviews = [makeReview({ userId: 'user-5' })];
      expect(canUserReview('user-99', template, reviews)).toBe(true);
    });
  });

  // ── formatPrice ───────────────────────────────────────────────────────────
  describe('formatPrice', () => {
    it('should format BRL price', () => {
      expect(formatPrice(29.9, 'BRL')).toBe('R$ 29,90');
    });

    it('should format USD price', () => {
      expect(formatPrice(29.9, 'USD')).toBe('$29.90');
    });

    it('should return "Grátis" for price 0 (BRL)', () => {
      expect(formatPrice(0, 'BRL')).toBe('Grátis');
    });

    it('should return "Grátis" for price 0 (USD)', () => {
      expect(formatPrice(0, 'USD')).toBe('Grátis');
    });

    it('should format large BRL price', () => {
      expect(formatPrice(1299.99, 'BRL')).toBe('R$ 1299,99');
    });
  });
});
